package com.agrios.platform.tasks.api;
import com.agrios.platform.common.web.TenantContextResolver; import com.agrios.platform.tasks.application.RecurringTaskService; import jakarta.servlet.http.HttpServletRequest; import jakarta.validation.Valid; import java.time.Instant; import java.util.UUID; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/v1/task-schedules") public class RecurringTaskController {private final RecurringTaskService service;private final TenantContextResolver tenants;public RecurringTaskController(RecurringTaskService s,TenantContextResolver t){service=s;tenants=t;} @PostMapping RecurringTaskDtos.Response create(@Valid @RequestBody RecurringTaskDtos.CreateRequest b,HttpServletRequest r){return service.create(tenants.resolve(r).tenantId(),actor(),b);}@PostMapping("/generate-due") int generate(@RequestParam Instant through,HttpServletRequest r){return service.generateDue(tenants.resolve(r).tenantId(),actor(),through);}private UUID actor(){return UUID.nameUUIDFromBytes("development-actor".getBytes());}}
